"use client";

import { useState, useRef, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { MessageCircle, X, Send, Bot, Paperclip, FileText, Sparkles } from "lucide-react";
import PortfolioPreview from "./PortfolioPreview";

const AIChat = () => {
  const [open, setOpen] = useState(false);
  const [messages, setMessages] = useState<{ role: "user" | "ai"; text: string }[]>([
    { role: "ai", text: "Hi! I'm an AI assistant powered by Groq. Ask me anything about this portfolio!" },
  ]);
  const [input, setInput] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [previewData, setPreviewData] = useState<any>(null);
  const [isDeploying, setIsDeploying] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const bottomRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, isLoading]);

  const handleSend = async () => {
    if ((!input.trim() && !selectedFile) || isLoading) return;

    setIsLoading(true);

    if (selectedFile) {
      // Handle file upload
      const formData = new FormData();
      formData.append("resume", selectedFile);

      setMessages((prev) => [...prev, { role: "user", text: `📎 Uploaded Resume: ${selectedFile.name}` }]);
      setSelectedFile(null); // Clear after sending visually

      try {
        const res = await fetch(`/api/ai/upload-resume`, {
          method: "POST",
          body: formData,
        });
        const data = await res.json();

        if (data.success && data.parsedResume && data.portfolioContent) {
          setMessages((prev) => [
            ...prev,
            { role: "ai", text: "I've generated a preview of your portfolio content. You can review it and click 'Deploy' when you're ready!" },
          ]);
          setPreviewData({
            name: data.parsedResume.name || "Developer",
            resumeData: data.parsedResume,
            ...data.portfolioContent
          });
        } else {
          setMessages((prev) => [
            ...prev,
            { role: "ai", text: data.error || "Failed to process the resume." },
          ]);
        }
      } catch {
        setMessages((prev) => [
          ...prev,
          { role: "ai", text: "⚠️ Error uploading resume to the backend." },
        ]);
      }
    } else {
      // Handle normal text message
      const userMsg = input.trim();
      setMessages((prev) => [...prev, { role: "user", text: userMsg }]);
      setInput("");

      try {
        const res = await fetch(`/api/ai`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ message: userMsg }),
        });
        const data = await res.json();
        setMessages((prev) => [
          ...prev,
          { role: "ai", text: data.reply || "No response received." },
        ]);
      } catch {
        setMessages((prev) => [
          ...prev,
          { role: "ai", text: "⚠️ Could not reach the AI backend. Please try again later." },
        ]);
      }
    }

    setIsLoading(false);
  };

  const handleDeploy = async () => {
    if (!previewData || isDeploying) return;

    setIsDeploying(true);
    try {
      const res = await fetch(`/api/ai/deploy-portfolio`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          name: previewData.name,
          resumeData: previewData.resumeData, // Add this
          portfolioContent: {
            headline: previewData.headline,
            about: previewData.about,
            skillsSummary: previewData.skillsSummary,
            projects: previewData.projects
          }
        }),
      });
      const data = await res.json();

      if (data.success) {
        setMessages((prev) => [
          ...prev,
          { role: "ai", text: `🚀 Portfolio deployed successfully! ID: ${data.template.portfolioId}. You can find your files in the server's generated-portfolios folder.` },
        ]);
        setPreviewData(null); // Close preview after success
      } else {
        setMessages((prev) => [
          ...prev,
          { role: "ai", text: data.error || "Deployment failed." },
        ]);
      }
    } catch {
      setMessages((prev) => [
        ...prev,
        { role: "ai", text: "⚠️ Could not connect to the deployment server." },
      ]);
    } finally {
      setIsDeploying(false);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const file = e.target.files[0];
      const validTypes = [
        "application/pdf",
        "application/vnd.openxmlformats-officedocument.wordprocessingml.document"
      ];

      if (validTypes.includes(file.type) || file.name.endsWith('.pdf') || file.name.endsWith('.docx')) {
        setSelectedFile(file);
        setInput(""); // Clear text input when file is selected
      } else {
        alert("Please upload a PDF or DOCX file.");
      }
    }
  };

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end gap-4">
      <AnimatePresence>
        {previewData && open && (
          <motion.div
            initial={{ opacity: 0, x: 20, scale: 0.95 }}
            animate={{ opacity: 1, x: 0, scale: 1 }}
            exit={{ opacity: 0, x: 20, scale: 0.95 }}
            className="w-[450px] mb-2"
          >
            <PortfolioPreview
              data={previewData}
              onDeploy={handleDeploy}
              isLoading={isDeploying}
            />
          </motion.div>
        )}
      </AnimatePresence>

      <AnimatePresence>
        {open && (
          <motion.div
            initial={{ opacity: 0, y: 20, scale: 0.9 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: 20, scale: 0.9 }}
            className="glass-strong neon-glow-indigo mb-4 w-80 rounded-xl overflow-hidden"
          >
            <div className="flex items-center justify-between px-4 py-3 border-b border-border">
              <div className="flex items-center gap-2">
                <Bot className="w-5 h-5 text-primary" />
                <span className="text-sm font-semibold text-foreground">AI Assistant</span>
              </div>
              <button onClick={() => setOpen(false)} className="text-muted-foreground hover:text-foreground">
                <X className="w-4 h-4" />
              </button>
            </div>

            <div className="h-64 overflow-y-auto p-4 space-y-3">
              {messages.map((msg, i) => (
                <div
                  key={i}
                  className={`flex ${msg.role === "user" ? "justify-end" : "justify-start"}`}
                >
                  <div
                    className={`max-w-[80%] px-3 py-2 rounded-lg text-xs leading-relaxed ${msg.role === "user"
                      ? "bg-primary text-primary-foreground"
                      : "bg-muted text-foreground"
                      }`}
                  >
                    {msg.text}
                  </div>
                </div>
              ))}
              {isLoading && (
                <div className="flex justify-start">
                  <div className="bg-muted text-foreground px-3 py-2 rounded-lg text-xs flex gap-1 items-center">
                    <span className="animate-bounce">●</span>
                    <span className="animate-bounce [animation-delay:0.15s]">●</span>
                    <span className="animate-bounce [animation-delay:0.3s]">●</span>
                  </div>
                </div>
              )}
              <div ref={bottomRef} />
            </div>

            <div className="p-3 border-t border-border flex flex-col gap-2 relative">
              {selectedFile && (
                <div className="absolute -top-10 left-3 right-3 bg-primary/20 border border-primary/30 rounded-md px-3 py-2 text-xs text-primary flex items-center justify-between backdrop-blur-sm z-10">
                  <div className="flex items-center gap-2 overflow-hidden">
                    <FileText className="w-3.5 h-3.5 flex-shrink-0" />
                    <span className="truncate">{selectedFile.name}</span>
                  </div>
                  <button onClick={() => setSelectedFile(null)} className="hover:text-primary-foreground ml-2">
                    <X className="w-3.5 h-3.5" />
                  </button>
                </div>
              )}

              <div className="flex gap-2 items-center relative z-20">
                <input
                  type="file"
                  ref={fileInputRef}
                  onChange={handleFileChange}
                  accept=".pdf,.docx"
                  className="hidden"
                />
                <button
                  onClick={() => fileInputRef.current?.click()}
                  disabled={isLoading}
                  className="p-2 rounded-lg text-muted-foreground hover:bg-muted hover:text-primary transition-colors disabled:opacity-50"
                  title="Upload Resume (PDF/DOCX)"
                >
                  <Paperclip className="w-4 h-4" />
                </button>

                <input
                  type="text"
                  value={input}
                  onChange={(e) => setInput(e.target.value)}
                  onKeyDown={(e) => e.key === "Enter" && handleSend()}
                  placeholder={
                    isLoading ? "AI is thinking..." :
                      selectedFile ? "Press Send to upload..." :
                        "Type a message..."
                  }
                  disabled={isLoading || selectedFile !== null}
                  className="flex-1 px-3 py-2 rounded-lg bg-muted/50 border border-border text-foreground text-xs placeholder:text-muted-foreground focus:outline-none focus:border-primary transition-colors disabled:opacity-50"
                />
                <button
                  onClick={handleSend}
                  disabled={isLoading || (!input.trim() && !selectedFile)}
                  className="p-2 rounded-lg bg-primary text-primary-foreground hover:shadow-[0_0_15px_hsl(var(--neon-cyan)/0.3)] transition-all disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  <Send className="w-3.5 h-3.5" />
                </button>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      <motion.button
        whileHover={{ scale: 1.1 }}
        whileTap={{ scale: 0.9 }}
        onClick={() => setOpen(!open)}
        className="w-14 h-14 rounded-full bg-primary text-primary-foreground flex items-center justify-center shadow-[0_0_30px_hsl(var(--neon-cyan)/0.4)] hover:shadow-[0_0_40px_hsl(var(--neon-cyan)/0.6)] transition-all"
      >
        {open ? <X className="w-6 h-6" /> : <MessageCircle className="w-6 h-6" />}
      </motion.button>
    </div>
  );
};

export default AIChat;
